UPDATE novel
novel_name = #{novelName}, author_id = #{authorId}, category_id = #{categoryId}, cover_image = #{coverImage}, content = #{content}, novel_status = #{novelStatus}, last_update_time = #{lastUpdateTime}, last_chapter_id = #{lastChapterId}, last_chapter_name = #{lastChapterName}, status = #{status}, updated_time = #{updatedTime}, deleted = #{deleted},
WHERE novel_id = #{novelId}

UPDATE novel
SET deleted = 1, updated_time = NOW()
WHERE novel_id = #{novelId}

UPDATE novel
SET click_count = click_count + 1
WHERE novel_id = #{novelId}

UPDATE novel
SET collect_count = collect_count + 1
WHERE novel_id = #{novelId}

UPDATE novel
SET recommend_count = recommend_count + 1
WHERE novel_id = #{novelId}

UPDATE novel
SET score = #{score}, score_count = score_count + 1, updated_time = NOW()
WHERE novel_id = #{novelId}
